import Vue from 'vue'
import { printf, sprintf, textWithLTR, _T } from '@@/utils/lang'
import '@@/assets/ar/css/login.scss'
import api, { loginWithFacebook2 } from '@@/api'
import { showModal } from '@@/components/modal/modal.vue'
import Dialog from '@@/components/modal/Dialog.vue'
import { getArgsFromUrl } from '@badam/common-utils'
import { formatTs, unregisterRemind, setUrlParams } from '@@/utils/func'
import { reportLoginClick, reportLoginFail } from '@@/utils/report'

export default Vue.extend({
  components: {},
  data() {
    return {
      loading: false,
      isRegister: !!getArgsFromUrl('is_register'),
    }
  },

  mounted() {
    localStorage.setItem('index_url', window.location.href)
    this.bindEvent()
    console.warn('JavaBridgeObj', JavaBridgeObj.wrapApi2)
    // this.showDialogTest()
    this.isRegister = !!getArgsFromUrl('is_register')
    console.log('in user mode >>', window.location.href, this.isRegister)
  },
  methods: {
    toCreate() {
      // location.href = `${location.href}&is_register=1`
      const url = setUrlParams('is_register', '1')
      location.href = url
    },
    bindEvent() {
      document.addEventListener('AppleIDSignInOnSuccess', (data) => {
        console.log('Apple Succeed', data)
      })
      document.addEventListener('AppleIDSignInOnFailure', (error: any) => {
        console.log('Apple Failed', error)
        const reason = error.detail.error
        reportLoginFail('baloot_apple', `APPLE_SERV FAIL ${reason}`)
      })
    },
    async onPressApple() {
      console.log(1, 'click apple', location.href)
      await reportLoginClick('baloot_apple')
      if (this.loading) {
        return
      }
      this.loading = true
      try {
        const data = await AppleID.auth.signIn()
        console.log(2, 'apple info', data)
        if (!data || !data.authorization || !data.authorization.id_token) {
          reportLoginFail('baloot_apple', 'APPLE_SERV FAIL NO TOKEN')
          this.loading = false
          return
        }
        const { code: apple_uid, id_token: apple_token } = data.authorization
        this.doLoginApple(apple_uid, apple_token, this.isRegister)
      } catch (error) {
        this.loading = false
      }
    },
    async onPressFacebook() {
      console.log(1, 'click facebook login2')
      await reportLoginClick('baloot_fb')
      if (this.loading) {
        return
      }
      this.loading = true
      FB.login((response: any) => {
        console.log(2, 'facebook info', response)
        if (!response.authResponse) {
          reportLoginFail('baloot_fb', 'FB_SERV FAIL NO TOKEN')
          this.loading = false
          return
        }
        const { userID: fb_uid, accessToken: fb_token } = response.authResponse
        this.doLoginFacebook(fb_uid, fb_token, this.isRegister)
      })
    },
    async doLoginFacebook(fb_uid: string, fb_token: string, auto_create = false) {
      const [success, accountResp] = await api.loginWithFacebook2(fb_uid, fb_token, auto_create)
      console.log(3, accountResp)
      this.loading = false
      if (!success) {
        reportLoginFail('baloot_fb', 'SAWA_SERV FAIL NOT 200')
        ;(this as any).$toast(_T('获取数据失败，请稍后重试'))
        this.loading = false
        return
      }
      if (accountResp.result !== 0) {
        this.loading = false
        if (accountResp.result === 20193) {
          unregisterRemind(accountResp)
          return
        }
        // 数据上报
        const e: any = {
          10001: '无baloot账号',
          20160: 'baloot账号登录，新注册的账号不支持',
        }
        const reportMsg = e[accountResp.result] || accountResp.message
        reportLoginFail('baloot_fb', `SAWA_SERV FAIL(${accountResp.result}) ${reportMsg}`)
        // 错误弹窗
        this.showDialog(accountResp, fb_uid, fb_token, 'fb')
        return
      }
      this.refreshAccount(accountResp, 'baloot_fb')
    },
    async doLoginApple(apple_uid: string, apple_token: string, auto_create = false) {
      const [success, accountResp] = await api.loginWithApple2(apple_uid, apple_token, auto_create)
      console.log(3, accountResp)
      this.loading = false
      if (!success) {
        reportLoginFail('baloot_apple', 'SAWA_SERV FAIL NOT 200')
        ;(this as any).$toast(_T('获取数据失败，请稍后重试'))
        this.loading = false
        return
      }
      if (accountResp.result !== 0) {
        this.loading = false
        if (accountResp.result === 20193) {
          unregisterRemind(accountResp)
          return
        }
        // 数据上报
        const e: any = {
          10001: '无baloot账号',
          20160: 'baloot账号登录，新注册的账号不支持',
        }
        const reportMsg = e[accountResp.result] || accountResp.message
        reportLoginFail('baloot_apple', `SAWA_SERV FAIL(${accountResp.result}) ${reportMsg}`)
        // 错误弹窗
        this.showDialog(accountResp, apple_uid, apple_token, 'apple')
        return
      }
      this.refreshAccount(accountResp, 'baloot_apple')
    },
    refreshAccount(accountResp: any, source: string) {
      console.log(4, 'login ok', accountResp)
      if (getArgsFromUrl('stay')) {
        return
      }
      const { identities, user_info } = accountResp.data
      // 只有1个身份的情况
      if (user_info) {
        const { session_key, uid, icon_verify } = user_info
        const o = { session_key, uid, icon_verify }
        const v = encodeURIComponent(JSON.stringify(o))
        window.location.href = `sawaksa://baloot_login/?baloot_acount=${v}&source=${source}`
        return
      }
      // 多个身份的情况
      const b = (identities || []).map((e: any) => e.login_key)
      const u = encodeURIComponent(JSON.stringify(b))
      window.location.href = `sawaksa://baloot_login/?identities=${u}&source=${source}`
    },
    showDialog(accountResp: any, uid: string, token: string, type: string) {
      const { result, message } = accountResp
      if (result === 20310) {
        showModal(Dialog, {
          item: {
            title: _T('创建账号'),
            content: _T('你还没有baloot账号，是否马上创建账号并登录sawa？'),
            confirmText: _T('确定'),
            cancelText: _T('取消'),
            confirmCallback: () => {
              if (type === 'fb') {
                this.doLoginFacebook(uid, token, true)
              } else if (type === 'apple') {
                this.doLoginApple(uid, token, true)
              }
            },
          },
        })
        return
      }

      let reason = _T('账号登录失败，请重新登录。')

      if (result === 20181) {
        reason = _T('所选账号已被停用，无法登录该账号。请重新登录。')
      } else if (result === 20001) {
        const banTo = +message
        if (banTo === -1) {
          reason = _T('因涉嫌违规，你的账号被永久封禁。你无法再登录该账号。')
        } else if (banTo > 0) {
          reason = sprintf(
            _T('因涉嫌违规，你的账号被封禁至%s，这段时间内你将无法登陆该账号。'),
            `<i>${formatTs(banTo)}</i>`
          )
        }
      }
      //
      showModal(Dialog, {
        item: {
          title: _T('登录失败'),
          content: reason,
          confirmText: _T('我知道了'),
          confirmCallback: () => {
            ;(window as any).location.href = localStorage.getItem('index_url')
          },
        },
      })
    },
    showDialogTest() {
      // this.showDialog(
      //   {
      //     result: 20001,
      //     message: Math.floor(+new Date() / 1000),
      //   },
      //   '0000',
      //   'ssss',
      //   'apple'
      // )

      const type = 'fb'
      const uid = 'xxxx'
      const token = 'xxx'

      showModal(Dialog, {
        item: {
          title: _T('创建账号'),
          content: _T('你还没有baloot账号，是否马上创建账号并登录sawa？'),
          confirmText: _T('确定'),
          cancelText: _T('取消'),
          confirmCallback: () => {
            if (type === 'fb') {
              this.doLoginFacebook(uid, token, true)
            } else if (type === 'apple') {
              this.doLoginApple(uid, token, true)
            }
          },
        },
      })
    },
    onPressPrivacy() {
      reportLoginClick('隐私政策')
      const link = 'https://arabpk-game.badambiz.com/html/about_en.html'
      window.location.href = link
    },
    onPressAgreement() {
      reportLoginClick('服务条款')
      const link = 'https://arabpk-game.badambiz.com/html/about_en.html'
      window.location.href = link
    },
  },
})
